const setup = $('⚙️ Setup').first().json;
const produkte = ($('🛍️ Produkte holen').first().json.products || [])
  .slice(0, 20)
  .map(p => '- ' + p.title + ' (' + setup.SHOP_URL + '/products/' + p.handle + ', ab ' + (((p.variants || [])[0] || {}).price || '?') + ')');

const orders = ($json.orders || []).filter(o => !o.cancelled_at);
const verkauft = {};
for (const o of orders) {
  for (const li of (o.line_items || [])) verkauft[li.title] = (verkauft[li.title] || 0) + li.quantity;
}
const topWoche = Object.entries(verkauft).sort((a, b) => b[1] - a[1]).slice(0, 3)
  .map(([name, menge]) => '- ' + name + ' (' + menge + 'x diese Woche)');

const prompt = 'Du bist Newsletter-Texter fuer den Onlineshop "' + setup.SHOP_NAME + '" (Nische: ' + setup.SHOP_NISCHE + ').\n\n' +
  'Produktkatalog (Auszug):\n' + produkte.join('\n') + '\n\n' +
  'Bestseller dieser Woche:\n' + (topWoche.length ? topWoche.join('\n') : '(keine Verkaeufe diese Woche)') + '\n\n' +
  (setup.NEWSLETTER_RABATT_CODE ? 'Rabattcode fuer den Newsletter: ' + setup.NEWSLETTER_RABATT_CODE + '\n\n' : '') +
  'Schreibe den kompletten Wochen-Newsletter auf Deutsch (Du-Form):\n' +
  '1. Betreffzeile (neugierig machend, max 45 Zeichen) + Preheader (max 80 Zeichen)\n' +
  '2. Aufhaenger: kurzer, persoenlicher Einstieg mit echtem Mehrwert zur Nische (Tipp, Insight oder Mini-Story - KEIN reines Verkaufen)\n' +
  '3. Produkt-Spotlight: 1-2 Produkte aus dem Katalog natuerlich einbinden, mit Link\n' +
  '4. Klarer CTA-Button (als <a> mit Inline-Button-Styling)\n' +
  (setup.NEWSLETTER_RABATT_CODE ? '5. Rabattcode elegant einbauen\n' : '') +
  '\nVerhaeltnis: 70% Mehrwert, 30% Verkauf. Mobiltaugliches HTML mit Inline-CSS.\n' +
  'Antworte NUR mit validem JSON, ohne Markdown-Codeblock: {"betreff": "...", "preheader": "...", "html": "<komplettes Newsletter-HTML>"}';

return [{ json: { prompt } }];

const blocks = $json.content || [];
const text = (blocks.find(b => b.type === 'text') || {}).text || '';
let daten;
try {
  daten = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch (e) {
  daten = { betreff: 'Dein Wochen-Newsletter (Entwurf)', preheader: '', html: text };
}
const setup = $('⚙️ Setup').first().json;
const hinweis = '<div style="background:#fef3c7;border:1px solid #f59e0b;padding:12px;border-radius:8px;font-family:sans-serif;font-size:13px;margin-bottom:20px;">' +
  '📰 <b>Newsletter-Entwurf</b> - Betreff: <b>' + daten.betreff + '</b> · Preheader: ' + (daten.preheader || '-') +
  '<br>Gegenlesen, in dein E-Mail-Tool (Shopify Email / Klaviyo / Mailchimp) kopieren und an deine Liste senden. 2 Minuten Arbeit.</div>';
return { json: {
  betreff: '📰 Newsletter-Entwurf fuer diese Woche: ' + daten.betreff,
  email_html: hinweis + daten.html
}};
